// Parse Claude's response defensively: strip fences, find {...}, null-fill.
const raw = ($json.content && $json.content[0] && $json.content[0].text) || '';
const cleaned = raw.replace(/```json/gi, '').replace(/```/g, '').trim();
const start = cleaned.indexOf('{');
const end = cleaned.lastIndexOf('}');

let parsed = {};
if (start !== -1 && end !== -1) {
  try { parsed = JSON.parse(cleaned.substring(start, end + 1)); } catch (e) { parsed = {}; }
}

const num = (v) => {
  const n = Number(v);
  return v === null || v === undefined || v === '' || !Number.isFinite(n) ? null : n;
};
const str = (v) => (typeof v === 'string' && v.trim() ? v.trim() : null);

return [{
  json: {
    employee_name: str(parsed.employee_name),
    role: str(parsed.role),
    start_date: str(parsed.start_date),
    end_date: str(parsed.end_date),
    salary_amount: num(parsed.salary_amount),
    salary_currency: str(parsed.salary_currency) ? String(parsed.salary_currency).toUpperCase() : null,
    notice_period: str(parsed.notice_period),
    probation_end: str(parsed.probation_end),
    vacation_days: num(parsed.vacation_days),
    sick_days: num(parsed.sick_days),
  },
}];
